      },
      {
        "conflict": "Pippen specified Retry-After as 'TTL of the current window key', but the sorted set approach has no per-window key with a meaningful TTL",
        "resolution": "Retry-After is now computed from the oldest entry in the sorted set: (oldest_score + 60) - now. This gives an accurate, dynamic value aligned with Pippen's intent of avoiding fixed values."
      }
    ],
